import DashboardCards from "../../components/dashboard/DashboardCards";

const DashboardPage = () => {

    const stats = {

        totalEmployees: 3,

        present: 2,

        pendingLeaves: 1,

        payroll: 235000

    };

    return (

        <>

            <h1>Dashboard</h1>

            <p>Welcome to Employee Management System.</p>

            <DashboardCards stats={stats} />

        </>

    );

};

export default DashboardPage;
